1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	const COMPONENT_PREMIUM = 25;
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	const MAIN_ITEM_PREMIUM: Record<string, number> = {
45	  sword: 100,
46	  amulet: 60,
47	  staff: 80,
48	  potion: 40,
49	};
50	
51	const INSURANCE_VALUE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
63	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
64	
65	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
66	const CURSE_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	const FOLLOWUP_DISCOUNT_RATE = 0.15;
72	const PROCESSING_FEE = 5;
73	const ROUNDING_PRECISION = 6;
74	
75	const componentBasePremium = (count: number): number => {
76	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
77	  return count * COMPONENT_PREMIUM;
78	};
79	
80	const COMPONENT_TYPES = ["rune", "moonstone"];
81	
82	const countByType = (items: Item[]): Map<string, number> => {
83	  const counts = new Map<string, number>();
84	  for (const { type } of items) {
85	    if (COMPONENT_TYPES.includes(type)) {
86	      counts.set(type, (counts.get(type) ?? 0) + 1);
87	    }
88	  }
89	  return counts;
90	};
91	
92	const componentsBasePremium = (items: Item[]): number => {
93	  const counts = [...countByType(items).values()];
94	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
95	};
96	
97	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
98	
99	const mainItemsBasePremium = (items: Item[]): number =>
100	  items.reduce((total, item) => total + itemBasePremium(item), 0);
101	
102	const policyBasePremium = (items: Item[]): number =>
103	  mainItemsBasePremium(items) + componentsBasePremium(items);
104	
105	const isHighEnchantment = (item: Item): boolean =>
106	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
107	
108	const itemSurcharge = (item: Item): number => {
109	  const base = itemBasePremium(item);
110	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
111	  const highEnchant = isHighEnchantment(item)
112	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
113	    : 0;
114	  return curse + highEnchant;
115	};
116	
117	const itemSurcharges = (items: Item[]): number =>
118	  items.reduce((total, item) => total + itemSurcharge(item), 0);
119	
120	const isLoyalCustomer = (customer: Customer): boolean =>
121	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
122	
123	const loyaltyDiscount = (base: number, customer: Customer): number =>
124	  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
125	
126	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
127	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
128	
129	const quotePremium = (
130	  items: Item[],
131	  customer: Customer,
132	  isFollowUp: boolean,
133	): number => {
134	  const base = policyBasePremium(items);
135	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
136	  const total =
137	    base +
138	    itemSurcharges(items) +
139	    firstInsurance -
140	    loyaltyDiscount(base, customer) -
141	    followUpDiscount(base, isFollowUp) +
142	    PROCESSING_FEE;
143	  return Math.ceil(Number(total.toFixed(ROUNDING_PRECISION)));
144	};
145	
146	const insuranceSum = (items: Item[]): number =>
147	  items.reduce((total, item) => total + (INSURANCE_VALUE[item.type] ?? 0), 0);
148	
149	const reimbursement = (amount: number, insuredItem: Item): number =>
150	  (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
151	    ? HIGH_ENCHANTMENT_PAYOUT_RATE * amount
152	    : amount;
153	
154	const damagePayout = (damage: Damage, insuredItem: Item): number =>
155	  reimbursement(damage.amount, insuredItem) - DEDUCTIBLE;
156	
157	const payoutForDamage = (damage: Damage, items: Item[]): number => {
158	  const insuredItem = items.find((item) => item.type === damage.itemType) as Item;
159	  return damagePayout(damage, insuredItem);
160	};
161	
162	const claimResult = (
163	  step: ClaimStep,
164	  scenario: Scenario,
165	): { payout: number; remainingCap: number } => {
166	  const policy = scenario.steps[step.policy] as QuoteStep;
167	  const cap = CAP_MULTIPLIER * insuranceSum(policy.items);
168	  const rawPayout = step.incident.damages.reduce(
169	    (total, damage) => total + payoutForDamage(damage, policy.items),
170	    0,
171	  );
172	  const payout = Math.floor(
173	    Number(Math.min(rawPayout, cap).toFixed(ROUNDING_PRECISION)),
174	  );
175	  return { payout, remainingCap: cap - payout };
176	};
177	
178	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
179	  let quoteCount = 0;
180	  const results = scenario.steps.map((step) => {
181	    if (step.op === "claim") {
182	      return claimResult(step, scenario);
183	    }
184	    const isFollowUp = quoteCount > 0;
185	    quoteCount += 1;
186	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
187	  });
188	  return { results };
189	};
